    source: 'cron-weekly'
  }
}];

// Set frequency = 'digest' for the downstream subscriber fetch
return [{
  json: {
    frequency: 'digest',
    date: new Date().toISOString().substring(0, 10),
    source: 'cron-digest'
  }
}];

// Render Newsletter HTML per subscriber (DE or EN)
// Input: items from Fetch Subscribers (one item per subscriber)
// Uses $('Fetch Today News').first().json for the news data
// Output: one item per subscriber with email + subject + html + headers + lastSentDate

const news = $("Fetch Today News").first().json;
if (!news || !news.items) {
  throw new Error('No news data available from Fetch Today News node');
}

const today = news.date || new Date().toISOString().substring(0, 10);
const lastSentDate = today;

const DE_MONTHS = ['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];
const EN_MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const d = new Date(today + 'T00:00:00Z');
const dateDe = `${d.getUTCDate()}. ${DE_MONTHS[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
const dateEn = `${EN_MONTHS[d.getUTCMonth()]} ${d.getUTCDate()}, ${d.getUTCFullYear()}`;

function escapeHtml(s) {
  return (s || '').toString()
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function cleanUrl(u) {
  try {
    const p = new URL(u);
    ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','fbclid','gclid'].forEach(k => p.searchParams.delete(k));
    let c = p.origin + p.pathname;
    if (p.search) c += p.search;
    return c;
  } catch (e) {
    return u || '';
  }
}

function itemDe(it) {
  const headline = escapeHtml(it.headline || '');
  const source = escapeHtml(it.source || '');
  const url = escapeHtml(cleanUrl(it.sourceUrl || it.url || ''));
  const desc = escapeHtml(it.descriptionDe || it.summary || '');
  return `<article style="margin-bottom:24px;"><h3 style="margin:0 0 4px 0;font-size:16px;font-family:Georgia,'Times New Roman',serif;">${headline}</h3><p style="margin:0 0 8px 0;font-size:12px;color:#888;">${source} · <a href="${url}" style="color:#b91c1c;">Weiterlesen →</a></p><p style="margin:0;font-size:14px;line-height:1.5;">${desc}</p></article>`;
}

function itemEn(it) {
  const headline = escapeHtml(it.headline || '');
  const source = escapeHtml(it.source || '');
  const url = escapeHtml(cleanUrl(it.sourceUrl || it.url || ''));
  const desc = escapeHtml(it.descriptionEn || it.summary || '');
  return `<article style="margin-bottom:24px;"><h3 style="margin:0 0 4px 0;font-size:16px;font-family:Georgia,'Times New Roman',serif;">${headline}</h3><p style="margin:0 0 8px 0;font-size:12px;color:#888;">${source} · <a href="${url}" style="color:#b91c1c;">Read more →</a></p><p style="margin:0;font-size:14px;line-height:1.5;">${desc}</p></article>`;
}

function renderDe(news, unsubUrl, dateDe) {
  const itemsHtml = (news.items || []).map(itemDe).join('');
  return `<!DOCTYPE html><html lang="de"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>KI-News · ${escapeHtml(dateDe)}</title></head><body style="font-family:-apple-system,'Segoe UI',Roboto,sans-serif;max-width:640px;margin:0 auto;padding:24px;color:#1a1a1a;background:#f0efec;"><h1 style="font-family:Georgia,'Times New Roman',serif;color:#b91c1c;margin:0 0 8px 0;">KI-News · ${escapeHtml(dateDe)}</h1><p style="font-style:italic;color:#555;line-height:1.5;margin:0 0 24px 0;">${escapeHtml(news.summaryDe || '')}</p><hr style="border:0;border-top:1px solid #ccc;margin:24px 0;">${itemsHtml}<hr style="border:0;border-top:1px solid #ccc;margin:24px 0;"><p style="font-size:12px;color:#999;">Levcon.ai · <a href="${escapeHtml(unsubUrl)}" style="color:#999;">Abmelden / Unsubscribe</a></p></body></html>`;
}

function renderEn(news, unsubUrl, dateEn) {
  const itemsHtml = (news.items || []).map(itemEn).join('');
  return `<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>AI News · ${escapeHtml(dateEn)}</title></head><body style="font-family:-apple-system,'Segoe UI',Roboto,sans-serif;max-width:640px;margin:0 auto;padding:24px;color:#1a1a1a;background:#f0efec;"><h1 style="font-family:Georgia,'Times New Roman',serif;color:#b91c1c;margin:0 0 8px 0;">AI News · ${escapeHtml(dateEn)}</h1><p style="font-style:italic;color:#555;line-height:1.5;margin:0 0 24px 0;">${escapeHtml(news.summaryEn || '')}</p><hr style="border:0;border-top:1px solid #ccc;margin:24px 0;">${itemsHtml}<hr style="border:0;border-top:1px solid #ccc;margin:24px 0;"><p style="font-size:12px;color:#999;">Levcon.ai · <a href="${escapeHtml(unsubUrl)}" style="color:#999;">Unsubscribe</a></p></body></html>`;
}

const siteUrl = ($env && $env.NEXT_PUBLIC_SITE_URL) || 'https://levcon.ai';
const out = [];

for (const sub of items) {
  const s = sub.json;
  const lang = (s.language || 'de').toLowerCase();
  const unsubToken = s.unsubscribeToken || s.id;
  const unsubUrl = `${siteUrl}/api/ai-news/unsubscribe?token=${encodeURIComponent(unsubToken)}`;

  let html, subject;
  if (lang === 'en') {
    html = renderEn(news, unsubUrl, dateEn);
    subject = `AI News · ${dateEn}`;
  } else {
    html = renderDe(news, unsubUrl, dateDe);
    subject = `KI-News · ${dateDe}`;
  }

  out.push({
    json: {
      email: s.email,
      subject,
      html,
      subscriberId: s.id,
      subscriberLanguage: lang,
      listUnsubscribe: `<mailto:news@levcon.ai?subject=Unsubscribe>, <${unsubUrl}>`,
      listUnsubscribePost: 'List-Unsubscribe=One-Click',
      lastSentDate
    }
  });
}

return out;

